// Parse enrichment + combine with classification + apply routing + escalation
const enrichRaw = $input.first().json.choices[0].message.content;
let cleaned = enrichRaw.trim().replace(/^```json\s*/, '').replace(/\s*```$/, '');
const enrichment = JSON.parse(cleaned);

// Get previous data
const prev = $('Parse Classification').first().json;
const message = prev.original_message;
const classification = prev.classification;

// ── STEP 4: ROUTING ──
const ROUTING_MAP = {
  'Bug Report': 'Engineering',
  'Feature Request': 'Product',
  'Billing Issue': 'Billing',
  'Technical Question': 'Engineering',
  'Incident/Outage': 'IT/Security'
};

let destination_queue;
let routing_reason;

if (classification.confidence_score < 70) {
  destination_queue = 'General/Triage';
  routing_reason = `Low confidence (${classification.confidence_score}%) — routed to triage`;
} else if (ROUTING_MAP[classification.category]) {
  destination_queue = ROUTING_MAP[classification.category];
  routing_reason = `Category '${classification.category}' maps to ${destination_queue}`;
} else {
  destination_queue = 'General/Triage';
  routing_reason = `Unknown category — routed to triage`;
}

// ── STEP 6: ESCALATION CHECK ──
const ESCALATION_KEYWORDS = ['outage', 'down for all users', 'billing error', 'critical', 'emergency', 'security breach', 'stopped loading', 'multiple users affected', 'down for', 'not working for everyone'];
const escalation_reasons = [];

// Check 1: Low confidence
if (classification.confidence_score < 70) {
  escalation_reasons.push(`Low confidence score: ${classification.confidence_score}%`);
}

// Check 2: Keywords
const msgLower = message.toLowerCase();
for (const keyword of ESCALATION_KEYWORDS) {
  if (msgLower.includes(keyword)) {
    escalation_reasons.push(`Escalation keyword detected: '${keyword}'`);
  }
}

// Check 3: Billing discrepancy > $500
const amounts = message.match(/\$[\d,]+(?:\.\d{2})?/g);
if (amounts && amounts.length >= 2 && classification.category === 'Billing Issue') {
  const values = amounts.map(a => parseFloat(a.replace('$', '').replace(',', '')));
  const discrepancy = Math.abs(values[0] - values[1]);
  if (discrepancy > 500) {
    escalation_reasons.push(`Billing discrepancy of $${discrepancy} detected (>$500)`);
  }
}

const escalation_flag = escalation_reasons.length > 0;

// Override routing if escalated
if (escalation_flag) {
  destination_queue = 'Escalation Queue';
  routing_reason = 'Escalated — ' + escalation_reasons.join('; ');
}

// ── BUILD FINAL RECORD ──
const record = {
  request_id: prev.request_id,
  source: prev.source,
  original_message: message,
  timestamp: new Date().toISOString(),
  classification: {
    category: classification.category,
    priority: classification.priority,
    confidence_score: classification.confidence_score
  },
  enrichment: {
    core_issue: enrichment.core_issue,
    identifiers: enrichment.identifiers,
    urgency_signal: enrichment.urgency_signal
  },
  routing: {
    destination_queue: destination_queue,
    routing_reason: routing_reason
  },
  escalation: {
    escalation_flag: escalation_flag,
    escalation_reasons: escalation_reasons
  },
  summary: enrichment.summary
};

return [{ json: record }];
